framework_css:
/*
  Design system and global reset
*/
:root {
  /* Color palette */
  --color-primary-red: #D0262C;
  --color-primary-black: #000000;

  --color-text-main: #555555;
  --color-text-muted: #777777;
  --color-text-strong: #000000;

  --color-border-subtle: #E5E5E5;
  --color-border-input: #D0D0D0;

  --color-bg-body: #FFFFFF;
  --color-bg-alt: #F7F7F7;
  --color-bg-control: #D0D0D0;

  --color-success: #2E7D32;
  --color-error: #C62828;
  --color-warning: #ED6C02;
  --color-info: #0277BD;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;

  --fs-h1: 32px;
  --fs-h2: 24px;
  --fs-h3: 20px;
  --fs-body: 15px;
  --fs-small: 13px;

  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
  --fw-semibold: 600;
  --fw-bold: 700;

  --lh-tight: 1.2;
  --lh-normal: 1.5;
  --lh-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  --radius-soft: 3px;
  --radius-pill: 999px;

  --header-height: 72px;
  --container-max-width: 1120px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--fs-body);
  line-height: var(--lh-normal);
  color: var(--color-text-main);
  background-color: var(--color-bg-body);
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

img {
  max-width: 100%;
  height: auto;
}

button {
  font-family: inherit;
  font-size: 100%;
}

.site-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.container {
  max-width: var(--container-max-width);
  margin: 0 auto;
  padding-left: var(--space-3);
  padding-right: var(--space-3);
}

/*
  Header
*/
.site-header {
  position: relative;
  z-index: 10;
  border-bottom: 1px solid var(--color-border-subtle);
  background-color: var(--color-bg-body);
}

.header-inner {
  display: flex;
  align-items: center;
  height: var(--header-height);
}

.header-left {
  flex: 0 0 auto;
}

.header-center {
  flex: 1 1 auto;
  text-align: center;
}

.header-right {
  flex: 0 0 auto;
  display: flex;
  align-items: center;
  gap: var(--space-2);
  margin-left: var(--space-2);
}

/* Logo (textual placeholder matching minimal style) */
.site-logo {
  display: inline-flex;
  align-items: baseline;
  gap: var(--space-0-5);
  font-family: var(--font-heading);
  font-size: 18px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--color-text-strong);
}

.logo-text-strong {
  font-weight: var(--fw-semibold);
}

.logo-text-light {
  font-weight: var(--fw-regular);
  color: var(--color-text-muted);
}

/* Primary navigation */
.primary-nav ul {
  list-style: none;
  margin: 0;
  padding: 0;
  display: inline-flex;
  align-items: center;
  gap: var(--space-3);
}

.primary-nav a {
  display: inline-block;
  padding: 4px 0;
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: var(--fw-regular);
  letter-spacing: 0.04em;
  text-transform: none;
  color: var(--color-text-main);
}

.primary-nav a:hover,
.primary-nav a:focus {
  color: var(--color-primary-black);
  text-decoration: underline;
}

.primary-nav .is-current > a {
  color: var(--color-primary-black);
  font-weight: var(--fw-medium);
}

/* Header search icon (visual only, matches screenshot) */
.header-search-icon {
  width: 18px;
  height: 18px;
  border-radius: var(--radius-pill);
  border: 2px solid var(--color-text-muted);
  position: relative;
}

.header-search-icon::after {
  content: '';
  position: absolute;
  right: -4px;
  bottom: -3px;
  width: 7px;
  height: 2px;
  background-color: var(--color-text-muted);
  transform: rotate(45deg);
  transform-origin: right center;
}

/* User avatar and dropdown */
.user-menu {
  position: relative;
}

.user-avatar {
  border: 1px solid var(--color-border-subtle);
  border-radius: 50%;
  width: 32px;
  height: 32px;
  padding: 0;
  background-color: var(--color-bg-alt);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
}

.user-avatar:focus-visible {
  outline: 2px solid var(--color-primary-red);
  outline-offset: 2px;
}

.avatar-initials {
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: var(--fw-medium);
  color: var(--color-text-main);
}

.user-dropdown {
  position: absolute;
  top: calc(100% + 8px);
  right: 0;
  min-width: 190px;
  border: 1px solid var(--color-border-subtle);
  background-color: #FFFFFF;
  padding: var(--space-1) 0;
  box-shadow: none;
  opacity: 0;
  transform: translateY(-4px);
  pointer-events: none;
  transition: opacity 120ms ease-out, transform 120ms ease-out;
}

.user-dropdown ul {
  list-style: none;
  margin: 0;
  padding: 0;
}

.user-dropdown li {
  margin: 0;
}

.user-dropdown a {
  display: block;
  padding: 6px var(--space-3);
  font-size: var(--fs-small);
  color: var(--color-text-main);
}

.user-dropdown a:hover,
.user-dropdown a:focus {
  background-color: var(--color-bg-alt);
  text-decoration: none;
}

.user-menu:hover .user-dropdown,
.user-menu:focus-within .user-dropdown {
  opacity: 1;
  transform: translateY(0);
  pointer-events: auto;
}

/*
  Content layout
*/
.site-content {
  flex: 1 0 auto;
  padding-top: var(--space-4);
  padding-bottom: var(--space-5);
}

.content-inner {
  /* matches main body margins in design */
}

.content-layout {
  display: flex;
  align-items: flex-start;
}

.content-primary {
  flex: 1 1 auto;
  padding-right: var(--space-5);
}

.content-sidebar {
  flex: 0 0 260px;
  padding-left: var(--space-4);
  border-left: 1px solid var(--color-border-subtle);
}

/* Placeholder typography for headings in content area */
.content-primary h1,
.content-primary h2,
.content-primary h3,
.content-sidebar h1,
.content-sidebar h2,
.content-sidebar h3 {
  font-family: var(--font-heading);
  color: var(--color-text-strong);
  margin-top: 0;
}

.content-primary h1 {
  font-size: var(--fs-h1);
  line-height: var(--lh-tight);
  font-weight: var(--fw-regular);
  margin-bottom: var(--space-3);
}

.content-primary h2 {
  font-size: var(--fs-h2);
  margin-bottom: var(--space-2);
}

.content-primary h3 {
  font-size: var(--fs-h3);
  margin-bottom: var(--space-2);
}

.content-primary p {
  margin-top: 0;
  margin-bottom: var(--space-1);
}

/* Optional sidebar widget styles (matching design patterns) */
.sidebar-widget {
  margin-bottom: var(--space-4);
  font-size: var(--fs-small);
}

.sidebar-widget-title {
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--fw-medium);
  margin: 0 0 var(--space-2) 0;
  color: var(--color-text-strong);
}

.sidebar-link-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.sidebar-link-list li {
  margin-bottom: var(--space-0-5);
}

.sidebar-link-list a {
  display: block;
  color: var(--color-text-main);
  font-size: var(--fs-small);
}

.sidebar-link-list a:hover,
.sidebar-link-list a:focus {
  color: var(--color-primary-black);
  text-decoration: underline;
}

/* Sidebar search control pattern */
.sidebar-search-form {
  display: flex;
  margin-bottom: var(--space-3);
}

.sidebar-search-input {
  flex: 1 1 auto;
  border: 1px solid var(--color-border-input);
  border-right: none;
  border-radius: 0;
  padding: 6px 8px;
  font-size: var(--fs-small);
}

.sidebar-search-button {
  flex: 0 0 auto;
  padding: 0 14px;
  border-radius: 0;
  border: 1px solid var(--color-border-input);
  background-color: var(--color-bg-control);
  color: var(--color-text-main);
  font-size: var(--fs-small);
  cursor: pointer;
}

.sidebar-search-button:hover,
.sidebar-search-button:focus {
  background-color: #C4C4C4;
}

/*
  Footer
*/
.site-footer {
  border-top: 1px solid var(--color-border-subtle);
  background-color: var(--color-bg-body);
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-2);
}

.footer-nav ul {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
}

.footer-nav a {
  font-size: var(--fs-small);
  color: var(--color-text-muted);
}

.footer-nav a:hover,
.footer-nav a:focus {
  color: var(--color-primary-black);
  text-decoration: underline;
}

.footer-meta {
  font-size: var(--fs-small);
  color: var(--color-text-muted);
}

/*
  Responsive adjustments
*/
@media (max-width: 960px) {
  .header-inner {
    flex-wrap: wrap;
    height: auto;
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
  }

  .header-center {
    order: 3;
    flex-basis: 100%;
    margin-top: var(--space-1);
  }

  .primary-nav ul {
    justify-content: center;
    row-gap: var(--space-1);
  }

  .content-layout {
    flex-direction: column;
  }

  .content-primary {
    padding-right: 0;
    margin-bottom: var(--space-4);
  }

  .content-sidebar {
    border-left: none;
    padding-left: 0;
  }
}

@media (max-width: 640px) {
  .primary-nav ul {
    gap: var(--space-1);
  }

  .primary-nav a {
    font-size: 13px;
  }
}
